  ('aboriginal-f0899a01-moex-00068', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依行政程序法規定，當事人或利害關係人得向行政機關申請閱覽有關資料，行政機關於例外情況下得 拒絕閱覽，下列何者不屬得拒絕之事由？', '["涉及國防、軍事、外交及一般公務機密，依法規規定無保密必要之部分", "有嚴重妨礙有關社會治安、公共安全之虞", "有侵害第三人權利之虞", "行政決定前之擬稿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00069', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列機關之行政行為，何者適用行政程序法之程序規定？', '["立法院", "臺北市議會", "臺灣高等法院", "嘉義縣政府"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00070', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於訴願法中訴願決定之敘述，下列何者錯誤？', '["訴願有理由者，受理訴願機關應以決定撤銷原行政處分，並得視事件之情節，逕為變更之決定", "訴願決定書之正本，應於決定後15日內送達訴願人、參加人及原行政處分機關", "訴願決定期間之延長以1次為限，最長不得逾3個月", "訴願決定書應附記，如不服決定，得於決定書送達之次日起2個月內向行政法院提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00071', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者於提起行政訴訟前應先經訴願程序？', '["確認訴訟", "一般給付訴訟", "不服經聽證程序而作成行政處分之救濟", "不服給予陳述意見機會而作成行政處分之救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00072', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲直轄市政府環境保護局與乙直轄市政府環境保護局依廢棄物清理法共同作成罰鍰處分，相對人應如 何提起訴願？', '["由相對人選擇向甲市政府或乙市政府提起訴願", "向行政院提起訴願", "向環境部提起訴願", "由相對人與二直轄市環境保護局協議，向甲市政府或乙市政府提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00073', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政處分效力之敘述，下列何者錯誤？', '["建築主管機關於核發建照前，先以電話通知申請人，申請人獲悉建築主管機關即將核發建照之時起， 建照即生效力", "通過會計師國家考試後，金融監督管理委員會核發會計師證書，當收受送達時，發生效力", "禁止停車之交通標線劃設完畢時，即生效力", "附負擔之行政處分依法送達相對人後，負擔亦即生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00074', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政訴訟之管轄與程序，下列敘述何者錯誤？', '["稅捐課徵事件所核課之稅額為新臺幣60萬元者，以高等行政法院高等行政訴訟庭為第一審法院", "交通裁決事件之裁判，得不經言詞辯論", "聲請收容，應由受收容人所在地之高等行政法院地方行政訴訟庭管轄", "高等行政法院地方行政訴訟庭不受理公務員免職處分之爭議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00075', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依憲法法庭裁判意旨，外籍人士申請居留簽證遭駁回，若其本國籍配偶欲提起行政訴訟救濟之，應提 起何種訴訟？', '["公益訴訟", "撤銷訴訟", "一般給付訴訟", "確認訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
